import os
import pickle
import tempfile
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import hashlib
import json

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'pkl', 'pickle'}
MAX_CONTENT_LENGTH = 100 * 1024 * 1024  # 100MB max file size
MODEL_DIR = 'models'

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_CONTENT_LENGTH

# Create directories
os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

# Security controls
ALLOWED_MODEL_TYPES = {
    'sklearn.linear_model.LinearRegression',
    'sklearn.ensemble.RandomForestClassifier',
    'sklearn.svm.SVC',
    'sklearn.tree.DecisionTreeClassifier'
}

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def validate_model_safety(model):
    """Validate model safety by checking its type and components"""
    try:
        # Get model type
        model_type = type(model).__module__ + '.' + type(model).__name__
        
        # Check if model type is allowed
        if model_type not in ALLOWED_MODEL_TYPES:
            return False
            
        # Additional safety checks can be added here
        return True
    except Exception:
        return False

def secure_pickle_load(file_path):
    """Secure pickle loading with validation"""
    try:
        with open(file_path, 'rb') as f:
            # Read and hash the file for verification
            file_content = f.read()
            file_hash = hashlib.sha256(file_content).hexdigest()
            
            # Load the model
            model = pickle.load(f)
            
            # Validate model safety
            if not validate_model_safety(model):
                raise ValueError("Model validation failed")
                
            return model, file_hash
    except Exception as e:
        raise ValueError(f"Failed to load model: {str(e)}")

@app.route('/upload', methods=['POST'])
def upload_model():
    try:
        if 'model' not in request.files:
            return jsonify({'error': 'No model file provided'}), 400
            
        file = request.files['model']
        
        if file.filename == '':
            return jsonify({'error': 'No file selected'}), 400
            
        if not allowed_file(file.filename):
            return jsonify({'error': 'Invalid file type'}), 400
            
        # Secure filename handling
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        
        # Save file
        file.save(file_path)
        
        # Load and validate model
        model, file_hash = secure_pickle_load(file_path)
        
        # Store model with secure naming
        model_id = file_hash[:16]  # Use first 16 chars of hash as ID
        model_save_path = os.path.join(MODEL_DIR, f"{model_id}.pkl")
        
        # Move file to permanent storage
        os.rename(file_path, model_save_path)
        
        return jsonify({
            'message': 'Model uploaded successfully',
            'model_id': model_id,
            'model_type': type(model).__module__ + '.' + type(model).__name__
        }), 200
        
    except ValueError as e:
        return jsonify({'error': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/predict/<model_id>', methods=['POST'])
def predict(model_id):
    try:
        # Load model
        model_path = os.path.join(MODEL_DIR, f"{model_id}.pkl")
        if not os.path.exists(model_path):
            return jsonify({'error': 'Model not found'}), 404
            
        with open(model_path, 'rb') as f:
            model = pickle.load(f)
            
        # Get input data
        data = request.get_json()
        if not data:
            return jsonify({'error': 'No input data provided'}), 400
            
        # Perform prediction
        prediction = model.predict([data['features']])
        
        return jsonify({
            'prediction': prediction.tolist()
        }), 200
        
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)